const items = $input.all();
const companies = [];

for (const item of items) {
  const body = item.json;
  let companyList = [];

  if (Array.isArray(body)) {
    companyList = body;
  } else if (body.companies && Array.isArray(body.companies)) {
    companyList = body.companies;
  } else if (body.data && Array.isArray(body.data)) {
    companyList = body.data;
  }

  for (const c of companyList) {
    const name = c.name || c.company_name || 'Unknown';
    const website = c.website || c.url || 'Unknown';
    const sector = c.tags && c.tags.length > 0 ? c.tags[0] : 'Unknown';
    const subsector = c.tags && c.tags.length > 1 ? c.tags[1] : 'Unknown';
    const city = c.city || 'Unknown';
    const country = c.country || 'Unknown';
    const techStack = c.tech_stack || 'Unknown';

    companies.push({
      json: {
        Company: name,
        Website: website,
        Careers_URL: website !== 'Unknown' ? website + '/careers' : 'Unknown',
        Country: country,
        City: city,
        Sector: sector,
        Subsector: subsector,
        Company_Stage: 'Startup',
        Company_Scale: 'Unknown',
        Employer_Category: 'YC',
        Remote: 'Unknown',
        Visa_Sponsorship: 'Unknown',
        EOR: 'Unknown',
        Hiring_Geography: 'Unknown',
        Target_Roles: 'Data Engineer, AI/ML Engineer',
        Tech_Stack: techStack,
        Region_Eligibility: 'Unknown',
        Portfolio_Theme_Match: 'Unknown',
        Language_Requirement: 'English',
        Hiring_Confidence: 'Medium',
        Reason_Match: 'YC company in AI/ML/Data domain',
        Source: 'YC Directory API',
        Cold_Outreach_Candidate: 'Yes',
        Visa_Sponsor_Register: 'Unknown'
      }
    });
  }
}

if (companies.length === 0) {
  return [{ json: { message: 'No companies found', raw: JSON.stringify(items[0]?.json).slice(0, 500) } }];
}

return companies;
